mapper.select:
SELECT a.id AS id, a.exam_details_uuid_number, a.users_id , a.exam_record_id, a.exam_question_id, a.exam_details_myanswer , a.exam_details_myscore , a.teacher_score, a.teacher_comment, a.review_status, a.exam_paper_topic_number, a.exam_paper_topic_sequence, a.create_time , a.update_time , eq.exam_question_name , eq.kemu_types , eq.exam_question_options , eq.exam_question_answer , eq.exam_question_analysis, eq.exam_question_types , eq.exam_question_sequence, u.nickname, u.avatar , u.phone , u.email, er.total_score, ept.exam_paper_topic_number AS exam_paper_topic_number FROM exam_details a LEFT JOIN exam_question eq ON a.exam_question_id = eq.id LEFT JOIN users u ON a.users_id = u.id LEFT JOIN exam_record er ON a.exam_record_id = er.id LEFT JOIN exam_paper_topic ept ON a.exam_question_id = ept.exam_question_id AND ept.exam_paper_id = er.exam_paper_id
AND a.exam_record_id = #{req.examRecordId}
AND a.exam_paper_id = #{req.examPaperId}
AND exam_question.exam_question_name LIKE CONCAT('%', #{req.examQuestionName}, '%')
AND u.nickname LIKE CONCAT('%', #{req.nickname}, '%')
AND a.id = #{req.id}
ORDER BY a.exam_paper_topic_sequence DESC, a.id ASC

SELECT a.id , a.exam_details_uuid_number , a.users_id, a.exam_record_id, a.exam_question_id, a.exam_details_myanswer , a.exam_details_myscore, a.teacher_score, a.teacher_comment, a.review_status, a.exam_paper_topic_number, a.exam_paper_topic_sequence, a.create_time , a.update_time , exam_question.exam_question_name , exam_question.kemu_types , exam_question.exam_question_options , exam_question.exam_question_answer , exam_question.exam_question_analysis , exam_question.exam_question_types , exam_question.exam_question_sequence , u.nickname, u.avatar , u.phone , u.email, ept.exam_paper_topic_number AS exam_paper_topic_number FROM exam_details a LEFT JOIN exam_question exam_question ON a.exam_question_id = exam_question.id LEFT JOIN users u ON a.users_id = u.id LEFT JOIN exam_paper_topic ept ON a.exam_question_id = ept.exam_question_id AND ept.exam_paper_id = (SELECT exam_paper_id FROM exam_record WHERE id = a.exam_record_id)
AND a.id = #{id}
ORDER BY a.exam_paper_topic_sequence ASC, a.id ASC
